SELECT performance_rating_name, COUNT(*) AS excellent_rating_count
FROM performance_ratings
WHERE performance_rating_id = 0;

SELECT work_life_balance_name
FROM work_life_balances
WHERE balance_score = (SELECT MAX(balance_score) FROM work_life_balances);

SELECT work_life_balance_name
FROM work_life_balances
WHERE balance_score > 30;

SELECT department_name, budget, AVG(headcount) OVER () AS avg_headcount
FROM departments
WHERE headcount > (SELECT AVG(headcount) FROM departments);

SELECT department_name, budget, headcount, AVG(headcount) OVER () AS average_headcount
FROM departments
WHERE budget > 2000000;

SELECT education_field_name, description 
FROM education_fields 
WHERE average_education_duration > 4;
